"""
MKT Original Commentary — Esther chapters 1–5
Run: python3 scripts/zc-original-esther-1-5.py
Verses: ch1×22 + ch2×23 + ch3×15 + ch4×17 + ch5×14 = 91
Key notes: highest Persian loanword density in OT; God's name absent (divine
providence is implicit); Haman the Agagite = renewed Amalek; Mordecai = Saul's tribe.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIG = {
  "1": {
    "1": "<p><em>bîmê ʾăḥašwērōš</em>: 'in the days of Ahasuerus.' The name <em>ʾăḥašwērōš</em> transcribes Old Persian <em>Xšayārša</em> (Greek <em>Xerxes</em>), the Achaemenid king who reigned 486–465 BCE. Esther contains more Persian loanwords than any other OT book — demonstrating authentic familiarity with Persian court culture. <em>hāʾōḥēz bᵉkol-malḵût wāmeḏî ûp̄āras</em>: 'ruling from India (<em>hōḏû</em>) to Ethiopia (<em>kûš</em>) over 127 provinces (<em>mᵉḏînôt</em>).' <em>Hōḏû</em> is the easternmost extent (Sanskrit India via Aramaic loanword); <em>kûš</em> is Nubia/Ethiopia, the southwestern limit. The 127 provinces may be symbolic (7×18+1) or reflect sub-provincial Achaemenid administrative units. The empire formula establishes the book's setting: a vast, multicultural empire whose administrative machinery will become both the threat to and instrument of Jewish survival.</p>",
    "2": "<p><em>bāyāmîm hāhēm kᵉšeḇet hammelek ʾăḥašwērōš ʿal kissēʾ malḵûtô</em>: 'in those days, when King Ahasuerus sat on his royal throne.' <em>Šeḇet</em> (sitting/residing) combined with the throne formula is the standard OT accession or establishment formula. <em>šûšan habîrāh</em>: 'Susa the citadel' — <em>bîrāh</em> is the same Aramaic loanword used in Neh 1:1 and Dan 8:2 for the fortified palace complex, borrowed from an Iranian original. Susa (modern Shush, southwestern Iran) was one of the four Achaemenid royal cities and served as the administrative winter capital. The Apadana (audience hall) and palace complex have been confirmed archaeologically. The double temporal marker — 'in those days' and 'when he sat on his throne' — signals stable, established rule.</p>",
    "3": "<p><em>baššānāh haššᵉlîšît lᵉmalḵûtô ʿāśāh mišteh</em>: 'in the third year of his reign he gave a banquet (<em>mišteh</em>).' The <em>mišteh</em> (drinking-feast, from <em>šāṯāh</em> = to drink) is Esther's primary social institution — the plot turns on three major banquets. Year 3 of Xerxes = 483 BCE, before his Greek campaign. The assembly of <em>ḥêl p̄āras ûmāḏay</em> (the army of Persia and Media) alongside princes and nobles may reflect planning for the 480 BCE Greek invasion. Esther consistently uses the formula 'Persia and Media' (not 'Media and Persia' as in Daniel), which aligns with the earlier Xerxes period when Persian precedence was unambiguous — a marker of authentic historical setting.</p>",
    "4": "<p><em>bᵉharʾōtô ʾet-ʿōšer kᵉḇôḏ malḵûtô</em>: 'displaying the great wealth of his kingdom.' <em>ʿŌšer</em> (wealth/riches) and <em>tip̄ʾeret</em> (splendor/glory) are the two dimensions of Persian royal self-presentation: material wealth and visual magnificence. <em>Yāmîm rabbîm šᵉmônîm ûmᵉʾat yôm</em>: 'many days — one hundred and eighty days.' The 180-day display of royal resources is extravagant even by ancient standards; the Persepolis treasury texts confirm the extraordinary wealth concentration in the Achaemenid court. The purpose is imperial propaganda: demonstrate to the military commanders from across the empire the resources available for the Persian war machine.</p>",
    "5": "<p><em>ûḇimlôʾt hayyāmîm hāʾēlleh ʿāśāh hammelek mišteh</em>: 'when those days were completed, the king gave another banquet.' The follow-on banquet for the people of <em>šûšan habîrāh</em> (Susa the citadel) proper, as opposed to the empire-wide gathering of princes, shows the layered social structure of Achaemenid court life. <em>Lᵉgān bîtat hammelek</em>: 'in the court of the garden-pavilion (<em>bîtān</em>) of the king's palace.' <em>Bîtān</em> is a hapax possibly related to Akkadian <em>bītu</em> (house) with a suffix, or a Persian loanword for a garden colonnade. The Persian royal garden — the <em>pardēs</em> (<em>paradeisos</em>) of Greek description — was a formal enclosed park adjacent to the palace, a microcosm of imperial order and abundance.</p>",
    "6": "<p><em>ḥûr karpas ûtᵉḵēlet ʾāḥûz bᵉḥaḇlê-ḇûṣ wᵉʾargāmān</em>: 'white and violet linens held with cords of fine linen and purple.' The verse's textile vocabulary is heavily Persian-influenced: <em>karpas</em> is a loanword (Sanskrit/Persian <em>karpāsa</em> = cotton/fine cloth); <em>bûṣ</em> = fine white linen; <em>ʾargāmān</em> = purple (possibly Akkadian <em>argamannu</em>). <em>ʿAl-gᵉlîlê kesef wᵉʿammûḏê šēš</em>: 'on silver rods and marble/alabaster columns.' <em>Šēš</em> = marble or alabaster (Egyptian loanword). <em>Mîṭôt zāhāḇ wākesef</em>: 'couches of gold and silver.' The luxury materials catalogue (white/violet curtains, silver rods, marble columns, gold-silver couches, mosaic pavement) corresponds closely to Persian palace archaeology at Susa and Persepolis — this is not generic ancient luxury but specifically Achaemenid décor.</p>",
    "7": "<p><em>wᵉhašqôt biklê zāhāḇ wᵉḵēlîm mikkēlîm šônîm</em>: 'drinking from golden vessels, each different from the others.' <em>Šônîm</em> (various, differing) — conspicuous variety as display of wealth. <em>Wᵉyên malkût rāḇ kᵉyaḏ hammelek</em>: 'and royal wine flowing freely according to the bounty of the king.' <em>Kᵉyaḏ hammelek</em> (according to the hand of the king) is a Persian-period formula for royal generosity — the same idiom as <em>yaḏ ʾĕlōhîm</em> (hand of God) in Ezra-Nehemiah but applied to royal patronage. The golden goblets contrast with the silver and bronze vessels of the Jerusalem temple (Ezra 1:9-11), highlighting Persian court opulence against the comparative poverty of the restoration community.</p>",
    "8": "<p><em>wᵉhaššᵉtiyyāh kaddāt ʾên ʾōnēs</em>: 'and drinking was according to the law — no one was compelled.' <em>Dāt</em> is one of Esther's most characteristic words — a Persian loanword (Old Persian <em>data</em> = law/edict) appearing 20 times in the book, more than anywhere else in the OT. The 'law' of the banquet was voluntary drinking — an unusual formality that signals Xerxes's liberality. <em>Kî-ḵēn yissaḏ hammelek ʿal kol-raḇ bêtô</em>: 'for the king had ordered all the officials of his household to do each man's pleasure.' This principle of individual freedom at the banquet contrasts sharply with the later irrevocable <em>dāt</em> of the Persians and Medes (1:19) that sentences Vashti and threatens the Jews — the same Persian legal concept covers both personal freedom and communal death sentence.</p>",
    "9": "<p><em>gam-waštî hammalḵāh ʿāśᵉtāh mištēh nāšîm</em>: 'also Queen Vashti gave a banquet for the women.' <em>Waštî</em> is a Persian name (cf. several Achaemenid queens with names ending in <em>-šti</em>). The parallel women's banquet reflects Persian court gender separation — the harem system required segregated social spaces. <em>Bêt hamalkût</em> (the royal palace) is differentiated from the king's garden court, suggesting the women's banquet was in the interior palace complex. Vashti does not appear in the Greek histories as Xerxes's queen (Amestris is attested); she may be a throne name, a different wife, or part of the story's narrative world distinct from strict historical record.</p>",
    "10": "<p><em>bayyôm haššᵉbîʿî kᵉṭôḇ lēḇ-hammelek bayyāyin</em>: 'on the seventh day, when the king's heart was good with wine.' <em>Ṭôḇ lēḇ</em> (good of heart) is the Hebrew idiom for festive happiness, here clearly implying intoxication. Seven eunuchs (<em>śārîsîm</em>) are named — Mehuman, Biztha, Harbona, Bigtha, Abagtha, Zethar, Carkas — all Persian names, confirming the court details' authenticity. <em>Śārîs</em> literally = eunuch but in Persian court usage referred more broadly to court officials (not necessarily physically castrated); the LXX renders as <em>eunouchos</em>. Their number (seven) parallels the seven counselors (v.14) and the seven-day feast — the book's careful sevens reflect both Persian court structure and the symbolism of completeness.</p>",
    "11": "<p><em>lᵉhāḇîʾ ʾet-waštî hammalḵāh lip̄nê hammelek bᵉketer malḵût</em>: 'to bring Queen Vashti before the king wearing the royal crown (<em>keter malḵût</em>).' The royal diadem identifies her as queen. The purpose: <em>lᵉharʾôt hāʿammîm wᵉhaśśārîm ʾet-yop̄yāh</em> = 'to display her beauty to the peoples and princes.' The command to display the queen to assembled males was, in Persian court protocol, a potential violation of harem customs that protected royal women from public view. Rabbinical interpretation debated whether the command was to appear wearing only the crown (nude display) or simply wearing it as a mark of queenly status — the text specifies only the crown, leaving the nature of the display ambiguous and generating centuries of interpretive debate.</p>",
    "12": "<p><em>wattᵉmāʾên hammalḵāh waštî lāḇôʾ biḏḇar hammelek</em>: 'but Queen Vashti refused to come at the king's command.' <em>Māʾēn</em> (to refuse) is strong and deliberate — not inability but willful refusal. <em>wayyiqṣōp̄ hammelek mᵉʾōḏ waḥămātô bāʿᵃrāh bô</em>: 'the king became furiously angry (<em>qāṣap̄</em>) and his wrath burned (<em>bāʿar</em>) in him.' Two anger verbs: <em>qāṣap̄</em> (sudden fury) and <em>bāʿar</em> (burning, smoldering anger) intensify each other. The narrator neither condemns nor justifies Vashti's refusal — it is simply the event that sets the plot in motion. Ancient and modern interpreters have debated whether she acts with courage, propriety, or merely inconvenient timing; the book's theology is indifferent to this question, concerned only with the providential chain of events her refusal initiates.</p>",
    "13": "<p><em>wayyōʾmer hammelek laḥăḵāmîm yōḏᵉʿê hāʿittîm</em>: 'and the king consulted the wise men who knew the times.' <em>Yōḏᵉʿê hāʿittîm</em> (knowers of the times) are royal counselors versed in astrology, law, and court precedent. The parallel phrase <em>yōḏᵉʿê dāt wādîn</em> (knowers of law and precedent) adds the legal dimension — both astrologers and legal advisers. <em>Kî-ḵēn dᵉḇar hammelek lip̄nê kol-yōḏᵉʿê dāt wādîn</em>: 'for such was the king's practice before all who knew law and precedent.' The consultation formula reflects actual Achaemenid royal practice: Ezra 7:14 confirms that Persian kings decided with the advice of seven counselors.</p>",
    "14": "<p><em>wᵉhaqārōḇ ʾēlāyw karᵉšenāʾ šēṯar ʾadmāṯāʾ tršîš meres marsᵉnāʾ ûmᵉmûḵān</em>: the seven counselors, all with demonstrably Persian names. The 'seven princes of Persia and Media who saw the king's face' (<em>rōʾê pᵉnê hammelek</em>) were a recognized class with direct royal access — Greek sources confirm Xerxes's seven noble advisers. The phrase <em>rōʾê pᵉnê hammelek</em> (those who see the king's face) is the technical term for inner-court access. The number seven matches the seven eunuchs (v.10) — the book's careful sevens reflect both Persian court structure and the symbolic completeness of the royal household's concentric rings of advisers.</p>",
    "15": "<p><em>kamāh laʿăśôt bammalḵāh waštî</em>: 'what should be done to Queen Vashti?' The legal question is precisely formulated: not what punishment Vashti deserves (presupposing guilt) but what the <em>dāt</em> requires. The offense: <em>ʾăšer lōʾ-ʿāśᵉtāh ʾet-maʾămar hammelek ʾăḥašwērōš bᵉyaḏ hassārîsîm</em> = 'she did not do the king's command delivered through the eunuchs' — disobedience to a royal command (<em>maʾămar</em>) through proper court channels (<em>bᵉyaḏ</em> = at the hand of). The legal precision is consistent with Persian administrative culture where written decrees and procedural correctness were paramount; the king cannot simply punish — he must consult the legal experts.</p>",
    "16": "<p><em>lōʾ ʿal-hammelek bilᵉḇaḏ ʿāwᵉṯāh waštî hammalḵāh</em>: 'Vashti has wronged not the king alone.' Memucan's argument expands the offense geometrically: Vashti wronged the king → all the princes → all the peoples in all provinces. The social cascade logic: women throughout the empire will cite Vashti's precedent to refuse their husbands. <em>Kî-yeṣēʾ dᵉḇar hammalḵāh ʿal-kol-hannāšîm</em>: 'for word of what the queen has done will go out to all women.' The verb <em>yāṣāʾ</em> (go out) — the same used for royal decrees — frames Vashti's refusal as a counter-decree propagating through the social order. The counselors' anxiety reveals a patriarchal order that rests on women's compliance and fears the contagion of one prominent refusal.</p>",
    "17": "<p><em>kî-yiqqāḵ dᵉḇar hammalḵāh ʿal-kol-hannāšîm lᵉḇazzôt baʿᵃlêhen</em>: 'the queen's act will cause all women to despise their husbands.' <em>Bāzāh</em> (to despise, hold in contempt) — used of Esau despising his birthright (Gen 25:34) and Michal despising David (2 Sam 6:16). The feared scenario: women will say 'King Ahasuerus commanded Vashti to come, but she did not come.' The argument from social precedent — bad example spreads — reframes a personal domestic incident as an imperial security concern. Whether the counselors genuinely fear this or are using the argument rhetorically to serve Memucan's interests (possibly he has a candidate for queenship?) is left for the reader to judge — the book's irony operates throughout ch. 1 at the counselors' expense.</p>",
    "18": "<p><em>wᵉhayyôm hazzeh tōʾmarnāh śārôt pāras ûmāḏay</em>: 'this very day the noblewomen of Persia and Media will say.' The urgency formula <em>hayyôm hazzeh</em> (this very day) reflects alarm. <em>śārôt pāras ûmāḏay</em>: noblewomen of both empires — the dual Persia-Media formula. The feared result: <em>kādāy bizzāyôn wāqāṣep̄</em> = 'there will be contempt and wrath.' The comic irony of ch. 1 operates throughout: the great Persian empire is depicted as destabilized not by military threat but by one woman's refusal to appear at a party. Memucan's solution — a universal edict commanding wifely honor — is equally disproportionate. The author's subtle humor at Persian imperial pretension is one of the book's literary pleasures.</p>",
    "19": "<p><em>wᵉyikkāṯēḇ bᵉdāṯê p̄āras-ûmāḏay wᵉlōʾ yaʿăḇôr</em>: 'and let it be written in the laws of Persia and Media so that it may not be altered.' The phrase <em>dāṯê p̄āras-ûmāḏay wᵉlōʾ yaʿăḇôr</em> (laws of Persia and Media which do not pass/change) introduces the central legal motif of the book. This principle appears also in Dan 6:8, 12, 15 (the law of the Medes and Persians which does not change) and is the pivot on which the entire plot turns: Haman's decree of death cannot be canceled, only countered with a second decree. The irrevocability of written Persian law is both historically plausible (Achaemenid administrative culture valued documentary permanence) and narratively essential — it creates the seemingly impossible situation from which only divine providence can extract the people.</p>",
    "20": "<p><em>wᵉnišmaʿ p̄iṯgam hammelek ʾăšer-yaʿăśeh bᵉḵol-malḵûtô</em>: 'when the king's decree (<em>piṯgam</em>) is proclaimed throughout his vast kingdom.' <em>P̄iṯgam</em> is a Persian loanword (Old Persian <em>patigāma</em> = message, command), appearing here and in Eccl 8:11 — one of Esther's characteristic Persian-administrative vocabulary items. The proposed edict's content — commanding wifely honor — is the comedic anti-climax: all the empire's bureaucratic machinery deployed to instruct every man to rule his household. The phrase <em>mimmᵉʾōnāh wᵉʿaḏ-qāṭān</em> (from the greatest to the least) is a standard merism for comprehensiveness — the edict applies universally, from the nobility to the commoners.</p>",
    "21": "<p><em>wayyîṭaḇ haddāḇār bᵉʿênê hammelek wᵉhaśśārîm wayyaʿaś hammelek kidᵉḇar mᵉmûḵān</em>: 'the thing pleased the king and the princes, and the king acted according to the word of Memucan.' The royal approval formula <em>wayyîṭaḇ bᵉʿênê</em> (it was good in the eyes of) is standard Hebrew. Memucan is the last counselor named (seventh) and his advice becomes royal policy — the king acts on the last voice heard. The pattern establishes the king's character: decisions are driven by advisers rather than independent judgment. This will be crucial later when Haman shapes the genocide decree and when Esther and Mordecai shape the counter-decree — the king is the instrument of whoever last has his ear.</p>",
    "22": "<p><em>wayyišlaḥ sᵉp̄ārîm ʾel-kol-mᵉḏînôt hammelek ʾel-mᵉḏînāh ûmᵉḏînāh kiktāḇāh wᵉʾel-ʿam wāʿam kilšônô</em>: 'he sent letters to all provinces, each in its own script and to each people in their own language.' The multilingual, multiscript royal communication is confirmed by Achaemenid administrative documents in Aramaic, Old Persian, Elamite, and Babylonian — the empire used each region's preferred administrative language. The final phrase (<em>lihyôt kol-ʾîš śōrēr bᵉḇêtô</em>: 'that every man should be master in his own house') is the edict's content — a thunderously trivial deployment of imperial power. The contrast between the elaborate administrative machinery and the banality of the message is the chapter's final ironic flourish, setting up the tone of subtle comedy that runs throughout the book.</p>"
  },
  "2": {
    "1": "<p><em>ʾaḥar haddᵉḇārîm hāʾēlleh kᵉšōḵaḵ ḥămat hammelek ʾăḥašwērōš zāḵar ʾet-waštî</em>: 'after these events, when King Ahasuerus's wrath had cooled, he remembered Vashti.' <em>Kᵉšōḵaḵ</em> (niphal of <em>šāḵaḵ</em> = to subside) — the anger has ebbed to regret. <em>Zāḵar</em> (he remembered) is theologically significant throughout the OT: divine remembrance initiates redemptive action (Gen 8:1; Exod 2:24; Neh 1:8). Here royal remembered regret sets the human chain in motion. The gap between events (Vashti's banishment, ch. 1 year 3) and Esther's presentation (ch. 2 year 7) historically corresponds to Xerxes's Greek campaign (480-479 BCE), ending in defeat. A humbled king returning from military disaster may have been more emotionally receptive to a new queen — the providential timing is precise.</p>",
    "2": "<p><em>wayyōʾmᵉrû naʿărê hammelek mᵉšārᵉṯāyw yᵉḇaqšû lammeleḵ nᵉʿārôt bᵉtûlôt ṭôḇôt marʾeh</em>: 'the king's servants said, let beautiful young virgins (<em>bᵉtûlôt</em>) be sought.' <em>Bᵉtûlāh</em> is the technical term for an unmarried woman of marriageable age whose virginity is legally presumed (different from <em>ʿalmāh</em>). The king's servants propose the beauty contest — the king does not initiate it. This passive royal posture (responding to advisers' suggestions throughout ch. 2) is consistent with ch. 1's portrayal of Ahasuerus as reactive rather than proactive, managed by his court as much as governing it. The mechanism of providence: Esther's rise to power comes through the ordinary operations of a pagan court, not through divine intervention visible to the characters.</p>",
    "3": "<p><em>wᵉyap̄qēd hammelek pᵉqîdîm bᵉḵol-mᵉḏînôt malḵûtô</em>: 'let the king appoint commissioners (<em>pᵉqîdîm</em>) throughout all his provinces.' <em>Pᵉqîdîm</em> (from <em>pāqaḏ</em> = to appoint/oversee/number) are administrative deputies. <em>Bêt hannāšîm</em>: 'the house of the women' (harem) — from Akkadian <em>bītu</em> (house). <em>El-yaḏ hêgê sᵉrîs hammelek šōmēr hannāšîm</em>: 'under the care of Hegai the king's eunuch, guardian of the women.' <em>Mārûqêhen</em>: 'their cosmetic preparations' (from <em>māraḵ</em> = to rub/smear) — the term appears only in Esther (2:3, 9, 12), referring to the elaborate Persian court beauty regimen for women being presented to the king: six months with oil of myrrh, six months with spices.</p>",
    "4": "<p><em>wᵉhannaarāh ʾašer tîṭaḇ bᵉʿênê hammelek timlōk taḥat waštî</em>: 'the young woman who pleases the king will reign instead of Vashti.' The verb <em>mālaḵ</em> (to reign) applied to the new queen is unusually strong — the same word used for royal reign. <em>Wayyîṭaḇ haddāḇār bᵉʿênê hammelek wayyaʿaś kēn</em>: 'the plan pleased the king and he did so.' The plan is efficient from a Persian court perspective: it produces a new queen while performing an empire-wide survey of available women, reinforcing the center's demographic reach into the provinces. From Esther's perspective, the beauty contest is the providential mechanism by which a Jewish exile reaches the position where she can save her people — the irony of imperial machinery becoming the vehicle of divine rescue.</p>",
    "5": "<p><em>ʾîš yᵉhûḏî hāyāh bᵉšûšan habîrāh ûšᵉmô morḏᵉḵay ben-yāʾîr ben-šimʿî ben-qîš ʾîš yᵉmînî</em>: 'there was a Jewish man in Susa, Mordecai son of Jair, son of Shimei, son of Kish — a Benjaminite.' The genealogy is the chapter's most theologically significant detail. <em>Mardᵉḵay</em> (Mordecai) transcribes the Babylonian name <em>Marduka</em>/<em>Mardukāya</em> (from the god Marduk), confirmed in Achaemenid administrative tablets from Persepolis. <em>Ben-Qîš ʾîš yᵉmînî</em>: 'son of Kish, a Benjaminite' — this is the same genealogical line as Saul (1 Sam 9:1: Kish the Benjaminite, father of Saul). This detail is not incidental: it establishes the Mordecai-Haman conflict as the renewed Saul-Agag/Benjamin-Amalek conflict. Saul failed to kill Agag (1 Sam 15); a descendant of Kish will complete the task.</p>",
    "6": "<p><em>ʾăšer hoglāh mîyrûšālaim ʿim-haggōlāh ʾašer-hoglᵉṯāh ʿim-yᵉḵonyāh</em>: 'who had been exiled from Jerusalem with Jeconiah.' The relative clause's antecedent is ambiguous — it could refer to Mordecai or Kish. If Mordecai, he was deported personally in 597 BCE (making him 86+ years old in 483 BCE — unlikely). More probably the antecedent is Kish (the great-grandfather), making Mordecai a second-generation exile. <em>Yᵉḵonyāh</em> = Jehoiachin/Coniah, deported in 597 BCE (2 Kgs 24:8-17). The Jeconiah connection places Mordecai's family among the leading families of Judah taken in the first deportation — before the 586 destruction — establishing an elite Babylonian exile background.</p>",
    "7": "<p><em>wayhî ʾōmēn ʾet-hadassāh hîʾ ʾestēr bat-dōḏô</em>: 'he had raised Hadassah — that is, Esther — his cousin.' <em>Hadassāh</em> (Hebrew name) = myrtle (<em>hadas</em>), a fragrant evergreen shrub associated with beauty and fertility. <em>ʾEstēr</em> (Persian name) likely from Old Persian <em>stāra</em> (star) or possibly related to Akkadian <em>Ishtar</em> (the goddess). The double name parallels Daniel/Belteshazzar and other exile figures: her Hebrew identity (<em>Hadassah</em>) is concealed while her Persian identity (<em>Esther</em>) is displayed. <em>Kî ʾên lāh ʾāḇ wāʾēm</em>: 'for she had neither father nor mother' — double orphanhood makes Mordecai both adoptive father and male protector. <em>Wayyiqqaḥ lô lᵉḇat</em>: 'and he took her as a daughter' — the formal adoption formula.</p>",
    "8": "<p><em>wayhî bᵉhiššāmaʿ dᵉḇar hammelek wᵉḏātô wayyiqqāḇeṣ nᵉʿārôt rabbôt</em>: 'when the king's decree was heard, many young women were gathered.' <em>Waytilqaḥ ʾestēr ʾel-bêt hammelek</em>: 'and Esther was taken to the king's house' — the passive (<em>tiqqāḥ</em>, niphal) emphasizes that Esther did not choose this; she was swept up by imperial machinery. <em>Wayyiqqaḥ</em> (he took) is the same root used for taking a wife — the harem entrance is a form of acquisition. Esther's passivity here (she was taken, gathered) stands in deliberate contrast to her later decisive initiative (4:16; 5:1-4): the narrative tracks her transformation from passive object of imperial power to active agent using that same power for her people's survival.</p>",
    "9": "<p><em>wayyiṭaḇ hannaʿărāh bᵉʿênāyw wayyiśśāʾ ḥeseḏ lᵉp̄ānāyw</em>: 'the young woman was pleasing in his eyes and she found loyal favor (<em>ḥeseḏ</em>) before him.' <em>Ḥeseḏ</em> (covenant loyalty, steadfast love) is the OT's most theologically loaded relational term. Its use for Esther's favor before Hegai gives even this secular relationship a providential coloring — the book's theology consistently uses the language of covenant relationship in the secular court setting. <em>Šeḇaʿ hamnᵉʿārôt hārᵉʾûyôt lātêt lāh mibbet hammelek</em>: 'seven young women selected from the king's house to give to her' — the number seven signals completeness and special status. Esther begins her harem residence with maximum institutional support.</p>",
    "10": "<p><em>lōʾ-higgîḏāh ʾestēr ʾet-ʿammāh wᵉʾet-môlaḏtāh</em>: 'Esther had not disclosed her people or her family background.' <em>ʿAm</em> (ethnic group/people) and <em>môleḏet</em> (birth/nativity) are the two components of Jewish identity Esther conceals. The reason: <em>kî morḏᵉḵay ṣiwwāh ʿāleyhā ʾašer lōʾ-taggîd</em>, 'for Mordecai had commanded her not to tell.' The concealment is not presented as sinful deception but as prudent survival strategy in a potentially hostile environment. It is also the plot's central mechanism: Esther's Jewish identity must be concealed until the moment of maximum risk (4:14-16) and maximum impact (7:3-4), when its revelation saves her people. The disclosure-concealment structure drives the narrative.</p>",
    "11": "<p><em>ûḇᵉḵol-yôm wāyôm morḏᵉḵay mithallek lip̄nê ḥăṣar bêt hannāšîm</em>: 'every day Mordecai walked back and forth before the harem courtyard.' <em>Hithallek</em> (reflexive of <em>hālaḵ</em> = to walk) describes a sustained daily practice — the same verb used for Enoch who 'walked with God' (Gen 5:22-24). The verb gives the practice a spiritual quality. Mordecai cannot enter but maintains daily presence; he exercises parental care under impossible circumstances. <em>Lāḏaʿat ʾet-šᵉlôm ʾestēr</em>: 'to learn about Esther's welfare (<em>šālôm</em>).' <em>Šālôm</em> (peace, wholeness, flourishing) — Mordecai seeks not just safety information but Esther's total wellbeing. The daily vigil establishes the emotional stakes of the subsequent crisis: this is not a political calculation but a father's care.</p>",
    "12": "<p><em>ûbᵉhaggiʿa tôr naʿărāh lāḇôʾ ʾel-hammelek</em>: 'when each young woman's turn (<em>tôr</em>) came to go before the king.' The twelve-month purification: six months with <em>šemen hammōr</em> (oil of myrrh — myrrh used in the sacred anointing oil, Exod 30:23-24) and six months with <em>habᵉśāmîm</em> (spices) and <em>tamrûqê hannāšîm</em> (women's cosmetics). <em>Mārûq</em> (cosmetic treatment, from <em>māraḵ</em> = to rub) appears only in Esther (2:3, 9, 12). The twelve-month preparation marks thoroughness and high stakes — one night with the king, then the second harem unless chosen as queen. The system is the book's starkest illustration of women's commodification under empire; the narrative does not endorse it but navigates its reality to arrive at Esther's unique agency.</p>",
    "13": "<p><em>kōl ʾăšer tōʾmar yinnāṭen lāh lāḇôʾ ʿimmāh mibêt hannāšîm ʿaḏ bêt hammelek</em>: 'whatever she asked was given to her to take with her from the women's house to the king's house.' The freedom to take whatever she chose — jewelry, clothing, attendants — is a significant privilege that tests each woman's judgment and taste. The choice of what to bring communicates character to the king. Esther's choice (v.15: only what Hegai advised) is the strategic wisdom that distinguishes her from the others — not striving for advantage through costly self-presentation but trusting the adviser with most knowledge of the king's actual preferences. The contrast between attempting to impress by accumulation and trusting expert guidance is a recurring wisdom motif.</p>",
    "14": "<p><em>bāʿereḇ hîʾ bāʾāh ûḇabboqer hîʾ šāḇāh ʾel-bêt hannāšîm šēnî</em>: 'in the evening she came, and in the morning she returned to the second harem.' The one-night protocol made selection entirely dependent on the king's sovereign choice — the women who did not please enough became concubines (<em>pîlagšîm</em>), unable to return to their families or marry another man yet without queen's status. <em>El-yaḏ šaʿašgaz sᵉrîs hammelek šōmēr happîlagšîm</em>: 'under the care of Shaashgaz the king's eunuch who guarded the concubines.' The system commodified women completely; the book's theology of providence is displayed precisely through this dehumanizing system being subverted to deliver Israel — the empire's mechanism of exploitation becomes the vehicle of salvation.</p>",
    "15": "<p><em>lōʾ-biqqᵉšāh dāḇār kî ʾim ʾet-ʾăšer yōʾmar hêgay</em>: 'she did not ask for anything except what Hegai advised.' Esther's distinctive strategy: unlike other women who presumably sought advantage through elaborate self-presentation, she deferred entirely to her most knowledgeable adviser. This is not passivity but strategic wisdom — identify the person with the most relevant knowledge and trust their counsel. <em>Waṯṯᵉhî ʾestēr nōśēʾt ḥēn bᵉʿênê kol-rōʾêhā</em>: 'and Esther was carrying (<em>nōśēʾt</em>) favor in the eyes of all who saw her' — the unusual participial construction (<em>nāśāʾ ḥēn</em> as ongoing attribute rather than single event) suggests an intrinsic, continuous quality rather than a situational response. Favor attaches to Esther as a permanent characteristic.</p>",
    "16": "<p><em>wattilāqaḥ ʾestēr ʾel-hammelek ʾăḥašwērōš baḥōḏeš hāʿăśîrî hûʾ-ḥōḏeš ṭēḇeṯ bišnat šeḇaʿ lᵉmalḵûtô</em>: 'Esther was taken to King Ahasuerus in the tenth month — Tebeth — in the seventh year of his reign.' <em>Ṭēḇeṯ</em> = December-January. Year 7 = 479 BCE, consistent with Xerxes's return from the failed Greek campaign. The four-year gap since Vashti's banishment (year 3 = 483 BCE) was filled by the Greek campaign: Xerxes crossed the Hellespont, burned Athens, but was defeated at Salamis (480 BCE) and Plataea (479 BCE) — the greatest Persian military humiliation. Esther enters the court at the moment of the king's return from this failure; the timing of her presentation to a chastened, emotionally receptive king is part of the book's providential narrative logic.</p>",
    "17": "<p><em>wayyeʾěhaḇ hammelek ʾet-ʾestēr mikkol-hannāšîm wattišśāʾ-ḥēn wāḥeseḏ lᵉp̄ānāyw mikkol-habᵉtûlôt</em>: 'the king loved Esther more than all the women, and she found grace and favor (<em>ḥēn wāḥeseḏ</em>) before him more than all the virgins.' Three terms for favor/love: <em>ʾāhaḇ</em> (love — the strongest term), <em>ḥēn</em> (grace, unearned favor), <em>ḥeseḏ</em> (steadfast love). The threefold love vocabulary intensifies what was said of each previous woman (they merely pleased) — Esther's reception is categorically different. <em>Wayyāśem keter-malḵût bᵉrōʾšāh wayyamliḵēhā taḥat waštî</em>: 'he set the royal crown (<em>keter malḵût</em>) on her head and made her queen instead of Vashti' — the coronation act completes the narrative arc from the opening verse.</p>",
    "18": "<p><em>wayyaʿaś hammelek mišteh gāḏôl lᵉḵol-śārāyw waʿăḇāḏāyw mištēh ʾestēr</em>: 'the king gave a great banquet — Esther's banquet.' The banquet is named for her: <em>mištēh ʾestēr</em> = 'Esther's feast,' an honorific. <em>Wᵉhānāḥāh lammᵉḏînôt ʿāśāh</em>: 'and he granted a remission (<em>hānāḥāh</em> = rest, relief, tax remission) to the provinces' — a standard royal coronation gift. <em>Wᵉyittēn maśśᵉʾt kᵉyaḏ hammelek</em>: 'and gave gifts according to the king's bounty.' <em>Maśśᵉʾt</em> (gift, lifting up, from <em>nāśāʾ</em> = to lift) — the king 'lifts' the burden from provinces in honor of the new queen. The public celebration of Esther's coronation has tangible economic consequences for the empire — her position immediately brings relief to the governed peoples, a harbinger of the larger salvation she will bring to her own people.</p>",
    "19": "<p><em>ûḇᵉhiqqāḇēṣ bᵉtûlôt šēnît ûmorḏᵉḵay yōšēḇ bᵉšaʿar hammelek</em>: 'when the virgins were gathered a second time, Mordecai was sitting at the king's gate.' The 'second gathering' is textually uncertain — commentators debate whether this is a resumptive narrative note or a distinct second collection. <em>Yōšēḇ bᵉšaʿar hammelek</em>: 'sitting at the king's gate' is a technical administrative term — gate-sitting was the position of judges and officials (Gen 19:1; Ruth 4:1-2; Deut 21:19). Mordecai has achieved some administrative status in Susa's bureaucracy, which places him at exactly the location where the assassination plot (v.21) will be overheard. The providential detail: his daily vigil for Esther's welfare (v.11) places him precisely where he needs to be to intercept the conspiracy.</p>",
    "20": "<p><em>ʾên ʾestēr maggiḏāh môlaḏtāh wᵉʿammāh kaʾăšer ṣiwwāh ʿāleyhā morḏᵉḵay</em>: 'Esther was still not revealing her family background or her people, just as Mordecai had commanded her.' The ongoing concealment even from the position of queen — <em>wᵉʾet-maʾămar morḏᵉḵay ʾestēr ʿōśāh</em>, 'Esther was doing what Mordecai commanded' — is narratively significant: despite her elevated position, the kinship bond persists. The narrator adds <em>kaʾăšer hāyᵉṯāh bᵉʾāmnāh ʾitô</em>: 'as when she was being raised by him' — the adoption relationship persists through radical change of circumstances. This verse will be echoed in reverse in 4:15-17 when Esther commands and Mordecai obeys — the relationship structure remains constant even as the direction of authority reverses.</p>",
    "21": "<p><em>bayyāmîm hāhēm ûmorḏᵉḵay yōšēḇ bᵉšaʿar hammelek qāṣap̄ bigṯān wāṯereš šᵉnê-sārîsê hammelek</em>: 'in those days, while Mordecai was sitting at the king's gate, Bigthan and Teresh became angry.' <em>Qāṣap̄</em> (became angry) — the same root as Ahasuerus's anger at Vashti (1:12); anger drives both the threat and the response in Esther. The two eunuchs guarded the threshold (<em>šōmᵉrê hassap̄</em>) — a position of intimate royal access. Their assassination plot (<em>lišlōaḥ yaḏ bᵉhammelek</em> = to lay a hand on the king) is overheard by Mordecai precisely because his daily vigil placed him at the gate. The discovery and reporting establishes the debt that the royal chronicles will record (v.23) but not immediately repay — the unrewarded act becomes the hinge of ch. 6's reversal.</p>",
    "22": "<p><em>wayyiqqāḏaʿ haddāḇār lᵉmorḏᵉḵay wayyaggēḏ lᵉʾestēr hammalḵāh wattōʾmer ʾestēr lammelek bᵉšēm morḏᵉḵay</em>: 'the matter became known to Mordecai, he told Queen Esther, and Esther told the king in Mordecai's name.' The intelligence chain: Mordecai → Esther → king. <em>Bᵉšēm morḏᵉḵay</em> (in Mordecai's name) — Esther could have claimed the credit but explicitly attributes it. This act of honest attribution ensures the royal chronicles record Mordecai's role accurately — the same chronicles that will be read aloud in 6:1-2 at the critical moment when Haman is planning Mordecai's execution. The book's providential structure depends on this single act of attribution: Esther's integrity in crediting Mordecai becomes the mechanism of his deliverance.</p>",
    "23": "<p><em>wayᵉḇuqqaš haddāḇār wayyimmāṣēʾ waytilû šᵉnêhem ʿal-ʿēṣ</em>: 'the matter was investigated, found to be true, and both were hanged on the gallows.' <em>ʿEṣ</em> (tree, wood, gallows) appears first here for the conspirators. The same word will be used for the gallows Haman builds for Mordecai (5:14) and on which Haman himself is hanged (7:9-10). The repeated <em>ʿēṣ</em> creates the book's central ironic image: the instrument of death threatening the innocent becomes the instrument of judgment on the guilty — the gallows reversal is Esther's central theological symbol. <em>Wayyikkāṯēḇ bᵉsēper diḇrê hayyāmîm lip̄nê hammelek</em>: 'it was written in the book of the chronicles before the king' — the recording that will be providentially read at 6:1-2, making it the most consequential book-entry in the narrative.</p>"
  },
  "3": {
    "1": "<p><em>ʾaḥar haddᵉḇārîm hāʾēlleh giḏdal hammelek ʾăḥašwērōš ʾet-hāmān ben-hammaḏāṯāʾ hāʾăgāgî</em>: 'King Ahasuerus promoted Haman the son of Hammedatha the Agagite.' <em>Hāmān</em> is an Elamite or Persian name; <em>Hammaḏāṯāʾ</em> is Persian (<em>Hamdātha</em> = gift of Haoma, the sacred plant). <em>Hāʾăgāgî</em> (the Agagite) is the genealogically explosive epithet: Agag was the Amalekite king Saul spared in violation of YHWH's command (1 Sam 15:8-9), resulting in Saul's rejection. The Agagite identification frames the narrative as renewal of the Saul-Agag conflict: Mordecai the Benjaminite (Saul's tribe and ancestral line) vs. Haman the Agagite (descendant of the king Saul should have killed). <em>Wᵉyāśem ʾet-kissᵉʾô mēʿal kol-haśśārîm</em>: 'set his seat above all princes' — Haman's elevation breeds the pride that a single non-bowing man will wound fatally.</p>",
    "2": "<p><em>wᵉḵol-ʿaḇdê hammelek ʾăšer bᵉšaʿar hammelek kōrᵉʿîm ûmištaḥăwîm lᵉhāmān kî-ḵēn ṣiwwāh lô hammelek</em>: 'all the king's servants bowed and prostrated themselves — for so the king had commanded.' <em>Kāraʿ</em> (to kneel/bow) and <em>hištaḥwāh</em> (to prostrate) are the two terms for full obeisance. The prostration was not voluntary deference but royal command. <em>Ûmorḏᵉḵay lōʾ yikraʿ wᵉlōʾ yištaḥăweh</em>: 'but Mordecai would not kneel or bow.' The categorical refusal — stated twice in the negative — is the narrative's pivot. The reason (given in v.4: because he is a Jew) frames the refusal as religious conscience overriding imperial command — the classic diaspora dilemma, paralleled in Dan 3 (refusing to bow to the statue) and Dan 6 (refusing to stop praying). For a Jew, obeisance to a human being could compromise the exclusive worship due YHWH; the specific Agagite identity may have made prostration additionally impossible.</p>",
    "3": "<p><em>wayyōʾmᵉrû ʿaḇdê hammelek maddûaʿ ʾattāh ʿôḇēr ʾēt miṣwat hammelek</em>: 'the king's servants said, why do you violate the king's command?' The interrogation by colleagues frames the issue as royal disobedience rather than religious principle — they use the language of legal violation (<em>ʿāḇar ʾet miṣwat hammelek</em> = transgress the king's command). Mordecai's answer (v.4) appeals to his Jewish identity. The collision between royal command and religious conscience is the recurring post-exilic dilemma (Dan 3, 6; Acts 4:19; 5:29). The colleagues' questioning before reporting to Haman shows they are testing whether the refusal is deliberate or accidental — ensuring the subsequent conflict is fully informed and that Mordecai's principled stance is unambiguous.</p>",
    "4": "<p><em>wayhî kᵉʾomrām ʾēlāyw yôm wāyôm wᵉlōʾ šāmaʿ ʾălêhem</em>: 'and when they had been speaking to him day after day (<em>yôm wāyôm</em>) and he would not listen.' The sustained daily pressure establishes Mordecai's refusal as consistent, principled stance — not a one-time oversight or misunderstanding. <em>Wayyaggîḏû lᵉhāmān lirʾôt hayya'amᵉḏû diḇrê morḏᵉḵay</em>: 'they reported to Haman to see whether Mordecai's behavior would be tolerated.' The colleagues are not merely informers but catalysts — they want the question resolved. <em>Kî-higgîḏ lāhem ʾăšer-hûʾ yᵉhûḏî</em>: 'for he had told them that he was a Jew' — Mordecai's own disclosure of his Jewish identity as the reason for refusal brings the latent Jew-Agagite conflict into the open where it must be resolved.</p>",
    "5": "<p><em>wayyarʾ hāmān kî-ʾên morḏᵉḵay kōrēaʿ ûmištaḥăweh lô wayyimmālēʾ hāmān ḥēmāh</em>: 'when Haman saw that Mordecai would not kneel or bow, Haman was filled with wrath (<em>ḥēmāh</em>).' <em>Ḥēmāh</em> is the strongest Hebrew anger word — burning rage demanding violent action. The same word is used for YHWH's anger in prophetic contexts (Isa 63:3; Jer 4:4; Ezek 8:18). Haman's disproportionate response — a single man's refusal produces genocidal fury — is characterologically diagnostic: he is constitutionally incapable of tolerating any challenge to his supremacy, however minor. The most powerful official in the Persian empire is undone by the indifference of a single gate-official — a portrait of the psychological fragility that lies beneath authoritarian power.</p>",
    "6": "<p><em>wayyiḇez bᵉʿênāyw lišlōaḥ yaḏ bᵉmorḏᵉḵay lᵉḇaḏô kî-higgîḏû lô ʾet-ʿam morḏᵉḵay</em>: 'he disdained to lay hands on Mordecai alone, for they had told him Mordecai's people.' <em>Bāzāh</em> (to despise, disdain) — the same contempt-vocabulary used in 1:17 (women despising their husbands). <em>Wayyᵉḇaqšēš hāmān lᵉhašmîḏ ʾet-kol-hayyᵉhûḏîm</em>: 'Haman sought to destroy all the Jews throughout the whole kingdom.' The logic of ethnic genocide: since the offender is representative of a people, the whole people becomes the target. This is the ideological structure of antisemitism — the individual Jew's behavior is taken as representative of Jewish collective threat, and the elimination of the individual is insufficient; the whole people must be eliminated. The personal grievance scales instantaneously to communal annihilation.</p>",
    "7": "<p><em>baḥōḏeš hārîʾšôn hûʾ-ḥōḏeš nîsān hippîl pûr hûʾ haggôrāl</em>: 'in the first month, Nisan, they cast Pur — that is, the lot.' <em>Pûr</em> is a Persian/Akkadian loanword (<em>pūru</em> = lot, stone used in divination) — the narrator explains it equals Hebrew <em>gôrāl</em> (lot), anticipating the naming of the festival of <em>Pûrîm</em> (9:26-28). The lot was cast through all twelve months to find the most auspicious day — it fell on the twelfth month, Adar, giving eleven months before the decree's execution. This providential timing (the lot that Haman casts as a tool of murder gives his intended victims eleven months to respond) is the book's most ironic reversal: the pagan instrument of divination becomes the means by which divine timing creates the space for salvation.</p>",
    "8": "<p><em>yešnô ʿam-ʾeḥāḏ mᵉp̄uzzār ûmᵉp̄ōrāḏ bên hāʿammîm bᵉḵol-mᵉḏînôt malḵûteḵā</em>: 'there is a certain people scattered and dispersed (<em>mᵉp̄uzzār ûmᵉp̄ōrāḏ</em>) throughout all the provinces of your kingdom.' The two participles emphasize the diaspora condition: dispersed widely, separated individually. Haman frames Jewish distinctiveness as imperial danger: their laws differ from every people (<em>wᵉdātêhem šōnôt mikkol-ʿām</em>), and they do not keep the king's laws. This is the perennial antisemitic accusation of dual loyalty — Jews have their own law that supersedes imperial law. The charge is not wholly inaccurate (Mordecai's refusal is an instance of Jewish law taking precedence) but is weaponized to justify genocide rather than to find accommodation.</p>",
    "9": "<p><em>waʾăšerāh ʿăśārāh kikkār-kesef ʿal-yᵉdê ʿōśê hamᵉlāʾḵāh lᵉhāḇîʾ ʾel-ginnᵉzê hammelek</em>: 'and I will pay ten thousand talents of silver into the king's treasury.' Ten thousand talents = approximately 375 metric tons of silver — more than the Persian empire's annual tribute by some estimates (Herodotus gives total satrapal tribute at c. 7,740 Euboic talents). The offer may be rhetorical or reflect Haman's genuine extraordinary wealth. The king's response (v.11: 'the silver is yours') suggests either he trusted Haman to fund it or the offer was a political formality. In any case, the transaction reduces an entire ethnic community to a commercial exchange: their lives are purchased as a court favor.</p>",
    "10": "<p><em>wayyāsar hammelek ʾet-tabbaʿtô mēʿal yāḏô wayyittᵉnāh lᵉhāmān ben-hammaḏāṯāʾ hāʾăgāgî ṣōrēr hayyᵉhûḏîm</em>: 'the king removed his signet ring (<em>tabbaʿat</em>) and gave it to Haman the Agagite, enemy (<em>ṣōrēr</em>) of the Jews.' <em>Tabbaʿat</em> (signet ring) — the instrument of royal authentication; documents sealed with the king's ring had royal authority. The transfer delegates power: Haman may now draft and seal decrees in the king's name. The narrator inserts the epithet <em>ṣōrēr hayyᵉhûḏîm</em> (adversary of the Jews) — from <em>ṣārar</em> (to press, show hostility), cognate with <em>śāṭān</em> (adversary). The king gives the ring without apparent inquiry into the target people — the casual disposal of a nation for court politics exposes the callousness of unchecked imperial power toward subject peoples.</p>",
    "11": "<p><em>wayyōʾmer hammelek lᵉhāmān hakkesef nātûn lāḵ wᵉhāʿām laʿăśôt bô kattôḇ bᵉʿênêḵā</em>: 'the silver is given to you, and the people — to do with them as seems good to you.' The double gift (money and people) reduces an entire ethnic community to disposable property. The king's response is chillingly casual: no inquiry about which people, no examination of the charges, no legal process. <em>Kattôḇ bᵉʿênêḵā</em> (as seems good to you) — unconstrained discretion. The phrase echoes the Judges refrain (<em>hayyāšār bᵉʿênāyw</em> = what was right in his own eyes, Judg 21:25): where Judges deplores the chaos of moral anarchy, Esther deplores the chaos of imperial moral abdication — both are conditions where human sovereignty, unaccountable to divine law, produces catastrophe.</p>",
    "12": "<p><em>wayyiqqārᵉʾû sōp̄ᵉrê hammelek baḥōḏeš hārîʾšôn bišlōšāh ʿāśār yôm bô</em>: 'the king's scribes were summoned on the thirteenth day of the first month.' The thirteenth of Nisan is the day before Passover — the irony is pointed: the day before Israel's great liberation festival, the decree for Israel's annihilation is written. <em>Wayṯikkāṯēḇ kᵉḵol-ʾăšer ṣiwwāh hāmān</em>: 'it was written exactly as Haman commanded.' The administrative machinery — scribes, satraps, governors, multiple scripts and languages — serves the genocide decree with the same efficiency it served the Cyrus liberation decree (Ezra 1:1-4). The bureaucratic apparatus is neutral; what it produces depends entirely on who controls it.</p>",
    "13": "<p><em>wᵉniślaḥ sᵉp̄ārîm bᵉyaḏ hārāṣîm ʾel-kol-mᵉḏînôt hammelek lᵉhašmîḏ lahărōg ûlᵉʾabbēd ʾet-kol-hayyᵉhûḏîm</em>: 'letters were sent ordering the destruction (<em>lᵉhašmîḏ</em>), killing (<em>lahărōg</em>), and annihilation (<em>lᵉʾabbēd</em>) of all the Jews.' The triple destruction formula intensifies with each verb — eliminate, kill, destroy. <em>Minnàʿar wᵉʿaḏ-zāqēn ṭap̄ wᵉnāšîm bᵉyôm ʾeḥāḏ</em>: 'from young to old, children and women, in one day' — the comprehensiveness covers every demographic. <em>Bišᵉlōšāh ʿāśār lᵉḥōḏeš šᵉnêm-ʿāśār hûʾ-ḥōḏeš ʾăḏār</em>: 'on the thirteenth of the twelfth month, Adar' — the lot-determined date. The date is providentially eleven months in the future, creating the narrative window for Esther's intervention.</p>",
    "14": "<p><em>patšegen hakkᵉtāḇ lᵉhinnātēn dāt bᵉḵol-mᵉḏînāh ûmᵉḏînāh lihyôt ʿătûḏîm layyôm hazzeh</em>: 'a copy (<em>patšegen</em>) of the document to be issued as law in every province, so that they would be ready for that day.' <em>Patšegen</em> is a Persian loanword (from Old Persian <em>patigāma</em> = copy/transcript), appearing only in Esther (3:14; 4:8; 8:13) — official administrative terminology for distributed decree copies. The advance notice — eleven months — is functionally designed to maximize participation in the killing, but providentially creates the window for Esther's counter-action. The decree's irrevocability (<em>lihyôt ʿătûḏîm</em> = to be prepared/ready) is the same legal permanence established in 1:19 — the wall that must be navigated rather than demolished.</p>",
    "15": "<p><em>hārāṣîm yāṣᵉʾû dᵉḥûpîm biḏḇar hammelek wᵉhaddāt nittᵉnāh bᵉšûšan habîrāh wᵉhammelek wᵉhāmān yāšᵉḇû lišᵉtôt</em>: 'the couriers went out urgently (<em>dᵉḥûpîm</em>) on the king's order, the decree was issued in Susa, and the king and Haman sat down to drink.' <em>Dᵉḥûpîm</em> (pushed, hurried) — the messengers of death dispatched with haste. The closing contrast is morally devastating: <em>wᵉhāʿîr šûšān nāḇôḵāh</em>, 'the city of Susa was thrown into confusion/turmoil.' <em>Nāḇôḵāh</em> (confused, in disarray) — even the non-Jewish population of Susa recognized the decree's wrongness, while the king and his favorite drank in indifference. The chapter ends with elite moral insulation and popular horror as the decree's two simultaneous realities — a portrait of power's capacity to generate suffering while its architects remain comfortable.</p>"
  },
  "4": {
    "1": "<p><em>ûmorḏᵉḵay yāḏaʿ ʾet-kol-ʾăšer naʿăśāh wayyiqraʿ morḏᵉḵay ʾet-bᵉgāḏāyw wayyilbaš śaq wāʾēper</em>: 'when Mordecai knew everything that had happened, he tore his garments, put on sackcloth and ashes.' The mourning ritual is immediate and complete: <em>qāraʿ bᵉgāḏāyw</em> (tore garments), <em>śaq wāʾēper</em> (sackcloth and ashes), and <em>wayyēṣēʾ bᵉṯôḵ hāʿîr wayyizʿaq zᵉʿāqāh gᵉḏôlāh ûmārāh</em> (went into the city crying a great and bitter cry). The <em>zᵉʿāqāh</em> (outcry) is the same word used for the oppressed people's cry to God (Exod 3:7, 9; Gen 18:20-21) — Mordecai's public mourning is both a social signal and an implicit appeal to divine attention. Positioning himself at the king's gate makes the mourning maximally visible: the news of Jewish lamentation will reach the queen through the court intelligence network.</p>",
    "2": "<p><em>wayyābôʾ ʿaḏ lip̄nê šaʿar hammelek kî ʾên lāḇôʾ ʾel-šaʿar hammelek bilᵉḇûš śāq</em>: 'he came as far as the king's gate entrance, for no one was permitted to enter the king's gate in mourning dress.' The prohibition against mourning-dress in the royal precinct reflects Persian court ideology: the royal presence is a space of perpetual celebration — death, grief, and defilement are excluded. The architectural limit (Mordecai at the gate, unable to enter) creates the narrative tension that makes Esther indispensable: his crisis cannot penetrate the royal space by normal means; only through Esther, who inhabits that space, can the message reach power. The gate-threshold is the spatial manifestation of Esther's pivotal mediating role.</p>",
    "3": "<p><em>ûḇᵉḵol-mᵉḏînāh ûmᵉḏînāh mᵉqôm ʾăšer dᵉḇar hammelek wᵉdātô maggîaʿ ʾēḇel gāḏôl layyᵉhûḏîm wᵉṣôm ûḇᵉḵî ûmispaḏ</em>: 'in every province where the king's decree arrived — great mourning among the Jews, with fasting, weeping, and wailing.' The mourning vocabulary is liturgical and communal: <em>ṣôm</em> (fasting), <em>bᵉḵî</em> (weeping), <em>mispēḏ</em> (formal lamentation), <em>śaq wāʾēper</em> (sackcloth and ashes). This is the covenant community's penitential response to crisis, seeking divine intervention through traditional means (cf. Joel 1:13-14; Jonah 3:5-8). The empire-wide Jewish mourning contrasts with the Persian capital's drinking (3:15) — two worlds responding entirely differently to the same decree, demonstrating that the Jews understand what Haman's decree means while the Persian court treats it as routine administration.</p>",
    "4": "<p><em>wattābōʾnāh naʿărôt ʾestēr wᵉsārîsêhā wayyaggîḏû lāh wattitḥalbāṭ hammalḵāh mᵉʾōḏ</em>: 'Esther's maids and eunuchs came and told her, and the queen was deeply distressed (<em>ḥibbāṭ</em>).' <em>Ḥibbāṭ</em> (niphal of <em>ḥāḇaṭ</em> = to beat/strike) — physically struck with anguish. <em>Wayyišlaḥ bᵉgāḏîm lᵉhalbîš ʾet-morḏᵉḵay</em>: 'she sent garments to clothe Mordecai' — to remove the sackcloth and restore normal appearance. Esther's initial response is to make the visible sign of mourning disappear, restoring the appearance of normalcy. <em>Wᵉlōʾ qibbēl</em>: 'but he did not accept.' Mordecai's refusal of the garments signals that this crisis cannot be managed by cosmetic restoration — it requires substantive response. Esther must move from the instinct to normalize to the decision to act.</p>",
    "5": "<p><em>wattiqrāʾ ʾestēr lᵉhătāḵ missārîsê hammelek ʾăšer heʿěmiḏ lᵉp̄ānêhā wattᵉṣawwêhû ʿal-morḏᵉḵay lāḏaʿat mah-zeh wᵉʿal-mah-zeh</em>: 'Esther summoned Hatach and charged him to find out what was happening and why.' <em>Hăṭāḵ</em> is likely a Persian name. Hatach serves as Esther's intermediary — she cannot leave the palace, Mordecai cannot enter; the intermediary bridges the spatial-political divide. The information-gathering phase (vv.5-9) precedes the response phase (vv.10-17), reflecting the narrative's interest in Esther's deliberate, considered decision process: she does not act without understanding, and understanding requires traversing the architectural boundary between the palace world and the Jewish world.</p>",
    "6": "<p><em>wayyēṣēʾ hăṭāḵ ʾel-morḏᵉḵay ʾel-rᵉḥôḇ hāʿîr ʾăšer lip̄nê šaʿar hammelek</em>: 'Hatach went out to Mordecai in the city square in front of the king's gate.' The geography is precise: Hatach crosses from the interior palace world (where Esther is) to the exterior city world (where Mordecai mourns in public). The <em>rᵉḥôḇ hāʿîr</em> (city broad-space/square) was the public gathering place — Mordecai's public mourning position. The physical traverse that Hatach makes is the narrative representation of the communication challenge Esther faces: the palace insulates her from her people; only the committed intermediary can bridge the divide. The spatial architecture of the palace system is also the spatial architecture of Jewish isolation within imperial power.</p>",
    "7": "<p><em>wayyaggēd-lô morḏᵉḵay ʾēt kol-ʾăšer qārāhû wᵉʾēt parāšat hakkesef</em>: 'Mordecai told him everything that had happened, including the precise amount of silver (<em>parāšat hakkesef</em>).' <em>Pāraš</em> (specification, exact detail) + <em>kesef</em> (silver) — the exact sum: ten thousand talents. This financial specificity is strategically important: Esther needs to understand that her people's death has been purchased — it is a commercial transaction, not a political policy. The revelation that Haman paid for the genocide transforms it from imperial administration into personal vendetta funded with private wealth. Understanding the transactional nature of the threat is essential for Esther to grasp both its seriousness and its vulnerability to counter-action within the same system.</p>",
    "8": "<p><em>wᵉʾet-patšegen kᵉtāḇ-haddāt ʾăšer nitten bᵉšûšan lᵉhašmîḏām nātan lô lᵉharʾôt ʾet-ʾestēr</em>: 'he gave him a copy (<em>patšegen</em>) of the written edict to show Esther.' <em>Patšegen</em> (official copy/transcript) — the document gives Esther irrefutable evidence. <em>Wᵉlᵉhaggîd lāh ûlᵉṣawwôt ʿāleyhā lāḇôʾ ʾel-hammelek lᵉḥallôt-lô ûlᵉḇaqqēš mippānāyw ʿal-ʿammāh</em>: 'to show her, tell her, and charge her to go to the king and entreat (<em>ḥillāh</em>) him for her people.' <em>Ḥillāh p̄ānîm</em> (to soften/entreat the face of) is the petition vocabulary normally used for approaching YHWH in prayer (Exod 32:11; 1 Sam 13:12; Ps 119:58) — the same sacred petition language is now applied to the human king, underscoring the scene's theological weight: Esther must perform before the king what Israel performs before God.</p>",
    "9": "<p><em>wayyābôʾ hăṭāḵ wayyaggēd lᵉʾestēr ʾēt diḇrê morḏᵉḵay</em>: 'Hatach came and reported Mordecai's words to Esther.' The brief report verse is the narrative hinge — Esther now possesses the information needed to make her decision. The three-part information exchange (Hatach to Mordecai, v.6; Hatach to Esther, v.9; Esther to Hatach to Mordecai, v.10) is completed: the message has traversed the architectural and political divide. What follows is Esther's deliberate response — first the naming of the obstacle (v.11), then the reception of Mordecai's challenge (vv.13-14), then the transformative decision (vv.15-16). The narrative slows here to register the weight of what Esther must decide.</p>",
    "10": "<p><em>wattōʾmer ʾestēr lᵉhăṭāḵ wattᵉṣawwēhû ʾel-morḏᵉḵay</em>: 'Esther spoke to Hatach and charged him to go back to Mordecai.' The symmetry of the exchange is precise: Hatach to Mordecai (v.6) → to Esther (v.9) → Esther sends Hatach back (v.10). The formality of the intermediary system reflects both Persian court protocol and the narrative's interest in building deliberateness: this is not a hurried exchange but a measured sequence of messages through a trusted channel. Each leg of the communication requires its own authorization — Esther 'charges' (<em>ṣiwwāh</em>) each movement, maintaining the chain of command even in crisis communication.</p>",
    "11": "<p><em>kol-ʾîš wᵉʾiššāh ʾăšer-yāḇôʾ ʾel-hammelek ʾel-heḥāṣēr happᵉnîmît ʾăšer lōʾ-yiqqārēʾ ʾaḥat dātô lᵉhāmîṯ</em>: 'for any man or woman who enters the inner court without being summoned — one law (<em>dāt</em>): to be put to death (<em>lᵉhāmîṯ</em>).' The death sentence for unsummoned entry to the inner court is the absolute obstacle Esther faces. The exception: <em>lᵉḇad mimmen ʾăšer yôšîṭ lô hammelek ʾet-šarḇiṭ hazzāhāḇ wāḥāy</em> = 'except for the one to whom the king extends the golden scepter — that one lives.' The golden scepter is the symbol of royal grace overriding the death-law — the only mechanism by which the irrevocable <em>dāt</em> can be suspended. <em>Waʾănî lōʾ niqrêtî lāḇôʾ ʾel-hammelek zeh šᵉlōšîm yôm</em>: 'and I have not been summoned these thirty days' — the queen's position is less secure than it appears; favor must be renewed, and thirty days of silence is ominous.</p>",
    "12": "<p><em>wayyaggîḏû lᵉmorḏᵉḵay ʾēt diḇrê ʾestēr</em>: 'they reported Esther's words to Mordecai.' The bare report verse (matching v.9) marks the completion of the information exchange. Esther has named the obstacle in precise legal terms: the death law, the thirty-day silence, the need for the scepter. Mordecai must now reframe this obstacle as the very context that makes her position providentially significant (v.14). The reporting formula is unchanged whether the message is hopeful or discouraging — the intermediary faithfully transmits whatever is said. The narrative's use of this formulaic exchange structure keeps the reader aware that communication itself is fragile and requires deliberate effort in the palace system.</p>",
    "13": "<p><em>al-tᵉdammî bᵉnap̄šēḵ lᵉhimmālēṭ bêt hammelek mikkol-hayyᵉhûḏîm</em>: 'do not think (<em>dāmāh</em>) in your heart that you will escape in the king's house from all the Jews.' <em>Dāmāh</em> = to imagine, suppose, think — the verb targets Esther's possible self-consolation that palace location provides safety. Mordecai's challenge shatters this illusion: her Jewish identity (concealed but real) means the decree applies to her regardless of title or location. Moreover, being in the palace while doing nothing would be the worst possible outcome: saved by position while her people die, having failed to use the unique position for its intended purpose. The logic is covenantal: identity cannot be escaped, only embraced or betrayed.</p>",
    "14": "<p><em>rᵉwāḥ wᵉhaṣṣālāh yaʿămōḏ layyᵉhûḏîm mimāqôm ʾaḥēr</em>: 'relief (<em>rᵉwāḥ</em>) and deliverance (<em>haṣṣālāh</em>) will come to the Jews from another place (<em>māqôm ʾaḥēr</em>).' <em>Rᵉwāḥ</em> = breathing room, relief; <em>haṣṣālāh</em> = rescue (from <em>nāṣal</em> = to deliver — the exodus verb). <em>Māqôm ʾaḥēr</em> (another place) is the book's closest approach to naming God — <em>Māqôm</em> (the Place) became a rabbinic circumlocution for God. Mordecai's certainty that deliverance will come regardless is the book's most explicit statement of divine providence: YHWH's commitment to preserve his people is absolute; the only question is whether Esther will be its instrument. <em>ûmî yôḏēaʿ ʾim-lᵉʿēt kāzōʾt higgaʿt lammalḵût</em>: 'and who knows whether you have not come to the kingdom for such a time as this?' <em>ʿēt kāzōʾt</em> (such a time as this) — the providential kairos where position, crisis, and calling converge.</p>",
    "15": "<p><em>wattōʾmer ʾestēr lᵉhāšîḇ ʾel-morḏᵉḵay</em>: 'Esther sent this reply to Mordecai.' The brevity of the verse marks the transition: deliberation is complete. What follows (v.16) is not another question but a plan of action. The shift from passive recipient of information (vv.4-10) through obstacle-naming (v.11) through reception of Mordecai's challenge (vv.13-14) to active commander (vv.15-16) is Esther's character transformation. The reply formula is identical to the earlier reporting formulas — the same administrative language now carries the weight of heroic decision. The narrative's use of formulaic language throughout this chapter gives the breakthrough moment its understated power: it looks like another report, but it is the turning point of the book.</p>",
    "16": "<p><em>lēḵ kᵉnôs ʾet-kol-hayyᵉhûḏîm hannimṣāʾîm bᵉšûšan wᵉṣûmû ʿālay wᵉʾal-tōḵᵉlû wᵉʾal-tištû šᵉlōšet yāmîm laylāh wāyôm</em>: 'go, gather all the Jews in Susa, fast for me — do not eat or drink for three days, night and day.' The three-day total fast (day and night, unbroken) is the most intense penitential form, combining total abstinence with corporate solidarity. The corporate dimension — all the Jews of Susa — transforms Esther's personal risk into communal intercession. <em>Gam-ʾănî wᵉnaʿărōṯay ʾāṣûm kēn</em>: 'and I also with my young women will fast in the same way' — the leader joins the communal act rather than merely commanding it. <em>Waʾăšer ʾāḇaḏtî ʾāḇāḏtî</em>: 'if I perish, I perish.' Two Hebrew words expressing complete resignation — the infinitive absolute construction (<em>ʾāḇōḏ ʾāḇad</em>) expresses completeness: if death comes, it comes fully; the possibility cancels nothing. It is the OT's most concentrated expression of sacrificial courage.</p>",
    "17": "<p><em>wayyaʿăḇōr morḏᵉḵay wayyaʿaś kᵉḵōl ʾăšer-ṣiwwᵉṯāh ʿālāyw ʾestēr</em>: 'and Mordecai went away and did everything Esther commanded him.' The authority reversal is linguistically deliberate: in 2:10 and 2:20, Esther did everything Mordecai commanded; now Mordecai does everything Esther commanded. The identical command-obedience formula with roles exactly reversed marks the completion of Esther's transformation. The chapter ends with Esther in command and the community in prayer — the human preparation is complete. The narrative's silence about divine response (God is never named) makes the subsequent events speak for themselves: the king cannot sleep, reads the chronicles, discovers Mordecai's unrewarded act — the machinery of providence operates through the ordinary course of sleepless nights and bureaucratic records.</p>"
  },
  "5": {
    "1": "<p><em>wayhî bayyôm haššᵉlîšî wattilbaš ʾestēr malḵût</em>: 'on the third day Esther clothed herself with royalty (<em>malḵût</em>).' The third day marks action after the three-day fast of 4:16. <em>Wattilbaš malḵût</em>: literally 'she clothed herself with royalty/kingdom' — the word <em>malḵût</em> (kingship, royalty) rather than the usual <em>bigdê malḵût</em> (royal garments) may be intentional: she takes on the full identity and authority of queenship, not merely the costume. <em>Waṯṯaʿămōḏ baḥăṣar bêt-hammelek happᵉnîmît</em>: 'she stood in the inner court (<em>ḥăṣar… happᵉnîmît</em>) of the king's house' — the threshold whose law sentences her to death for unauthorized entry. She makes herself visible, positioning herself in the king's sight line before making any request. The entire approach is strategic: be seen before speaking, let the visual encounter establish favor before the verbal request is made.</p>",
    "2": "<p><em>wayhî kirʾôt hammelek ʾet-ʾestēr hammalḵāh ʿōmeḏet beḥāṣēr nāśᵉʾāh ḥēn bᵉʿênāyw</em>: 'when the king saw Queen Esther standing in the court, she found favor (<em>ḥēn</em>) in his eyes.' <em>Nāśᵉʾāh ḥēn bᵉʿênāyw</em>: 'she bore/carried favor in his eyes' — the same unusual participial construction as 2:15. The favor is presented as intrinsic to Esther rather than a royal decision: the king responds to something in her. <em>Wayyôšeṭ hammelek lᵉʾestēr ʾet-šarḇiṭ hazzāhāḇ</em>: 'the king extended the golden scepter (<em>šarḇiṭ hazzāhāḇ</em>) in his hand.' The scepter extension is the reprieve from the death sentence of 4:11 — the moment of divine favor made tangible in royal gesture. <em>Wattiqraḇ ʾestēr wattîgaʿ bᵉrōʾš haššarḇiṭ</em>: 'and Esther approached and touched the top of the scepter' — the touch completes the acceptance of grace: favor offered (scepter extended) and received (scepter touched).</p>",
    "3": "<p><em>wayyōʾmer lāh hammelek mah-lāḵ ʾestēr hammalḵāh ûmah-baqqāšāṯēḵ ʿaḏ-ḥᵉṣî hammalḵût wᵉyinnāṭēn lāḵ</em>: 'the king said, what is your petition, Queen Esther? It shall be granted to you, even to half the kingdom.' <em>ʿAḏ-ḥᵉṣî hammalḵût</em> (even to half the kingdom) is a standard ancient Near Eastern royal generosity formula — a hyperbolic offer of extreme favor (cf. Mark 6:23). It signals maximal readiness to grant whatever is within reason. The immediate generosity — before Esther speaks her petition — shows both the effectiveness of her approach (her clothed-in-royalty visual presentation) and the favorable reception the thirty-day absence had been building: the king missed her, and her appearing, having risked death to do so, demonstrates a devotion that moves him.</p>",
    "4": "<p><em>wattōʾmer ʾestēr ʾim-ʿal-hammelek ṭôḇ yāḇôʾ hammelek wᵉhāmān hayyôm ʾel-hammiště ʾăšer-ʿāśîtî lô</em>: 'if it pleases the king, let the king and Haman come today to the banquet I have prepared.' Esther defers her petition to the banquet — the delay strategy. This has generated extensive commentary: she may hesitate because the moment is not right, because she wants to ensure Haman's presence before making the accusation, because she needs divine confirmation, or because the providential narrative requires one more night for the insomniac king's chronicles-reading (ch. 6). Whatever the human motivation, the invitation converts the emergency court appearance into a controlled social event where royal generosity is maximized and the setting is most favorable for a life-or-death petition.</p>",
    "5": "<p><em>wayyōʾmer hammelek maharû ʾet-hāmān laʿăśôt ʾet-dᵉḇar ʾestēr</em>: 'the king said, bring Haman quickly so that what Esther desires may be done.' The king's enthusiasm — <em>maharû</em> (hurry! quickly!) — reflects his delight. Haman is summoned with the same urgency (<em>dᵉḥûpîm</em>, 3:15) that sent the genocidal couriers out — the mirror of the plot: the haste that spread the death decree now spreads the dinner invitation to the death decree's author. Haman arrives at the banquet unaware that the queen's hospitality is the prelude to his accusation. The dinner invitation that honors him is simultaneously the summons to his judgment — the book's structural irony operating at full capacity.</p>",
    "6": "<p><em>wayyōʾmer hammelek lᵉʾestēr bᵉmištehhayyin mah-šᵉʾēlāṯēḵ wᵉyinnāṭēn lāḵ ûmah-baqqāšāṯēḵ ʿaḏ-ḥᵉṣî hammalḵût wᵉtēʿāś</em>: 'at the wine banquet the king said, What is your petition? Up to half the kingdom it shall be done.' The wine banquet repetition of the throne room offer shows the king's continued generous posture. The setting — <em>bᵉmištehhayyin</em> (at the wine drinking) — mirrors the banquet of ch. 1 where wine played a destructive role (Vashti's humiliation). The book's banquet symmetry: what wine destroyed in ch. 1 (Vashti's queenship through an intemperate command), wine will enable in chs. 5-7 (Esther's victory through strategic hospitality). The <em>mišteh</em> institution frames both the problem and its resolution.</p>",
    "7": "<p><em>wattaʿan ʾestēr wattōʾmer šᵉʾēlātî ûḇaqqāšātî</em>: 'Esther answered, My petition and my request —' The sentence deliberately trails off — Esther begins to name her petition and then pivots to a second invitation. The rhetorical technique of beginning the answer and then deferring has been analyzed as theatrical suspense, strategic preparation of emotional context, or providential delay. The same night Esther delays, the king cannot sleep and reads the chronicles, leading to Mordecai's honor (ch. 6) — the delay that appears as Esther's hesitation is the hinge on which the entire reversal turns. Whether Esther knows this or not is left open; the book's theology of hidden providence does not require that its human instruments understand the divine timing they are participating in.</p>",
    "8": "<p><em>ʾim-māṣāʾtî ḥēn bᵉʿênê hammelek wᵉʾim-ʿal-hammelek ṭôḇ lātēt ʾet-šᵉʾēlātî wᵉlaʿăśôt ʾet-baqqāšātî yāḇôʾ hammelek wᵉhāmān ʾel-hammiště ʾăšer ʾeʿěśeh lāhem</em>: 'if I have found favor and if it pleases the king to grant my petition, let the king and Haman come to the banquet I will prepare.' Two conditional clauses of maximal deference before the actual request — Esther's language is calculated submission, not weakness. <em>Ûḇᵉḵāl-ûᵉmāḥār ʾeʿăśeh kidᵉḇar hammelek</em>: 'and tomorrow I will do as the king says' — she frames the second invitation as compliance with royal preference, giving the king what he wants (her hospitality) while she prepares what she needs (one more opportunity at the moment of maximum emotional readiness).</p>",
    "9": "<p><em>wayyēṣēʾ hāmān bayyôm hahûʾ śāmēaḥ wᵉṭôḇ lēḇ</em>: 'Haman went out that day joyful and glad of heart.' <em>Śāmēaḥ wᵉṭôḇ lēḇ</em> (joyful and good of heart) is the idiom for festive elation — the same phrase used of the populace at Esther's coronation (2:18) and at the Purim celebration (8:15). Haman leaves the banquet at the apex of his public life. <em>Ûkᵉrʾôt hāmān ʾet-morḏᵉḵay bᵉšaʿar hammelek wᵉlōʾ-qām wᵉlōʾ-zāʿ mimennû</em>: 'but when Haman saw Mordecai at the king's gate, and Mordecai neither rose nor trembled before him.' <em>Zāʿ</em> (trembled) — the expected response from an inferior to a superior was physical prostration and fear. Mordecai does neither: he does not rise (social acknowledgment) and does not tremble (emotional deference). <em>Wayyimmālēʾ hāmān ʿal-morḏᵉḵay ḥēmāh</em>: 'Haman was filled with rage against Mordecai.' The verb <em>mālaʾ</em> (to be filled) with <em>ḥēmāh</em> (burning wrath) describes a man whose entire emotional capacity is occupied by a single offense — the man who just emerged from a royal banquet in his honor cannot enjoy that honor because one gate-official refuses to acknowledge him. The psychological portrait is precise: authoritarian power requires total submission, and total happiness is destroyed by a single exception.</p>",
    "10": "<p><em>wayyitʾappaq hāmān wayyāḇôʾ ʾel-bêtô wᵉyišlaḥ wayyāḇēʾ ʾet-ʾōhăḇāyw wᵉʾet-zereš ʾišṯô</em>: 'Haman restrained himself (<em>wayyitʾappaq</em>) and went home, sending for his friends and his wife Zeresh.' <em>Hitʾappeq</em> (reflexive of <em>ʾāpaḳ</em> = to hold back) — to restrain oneself with effort; used of Joseph suppressing emotion (Gen 43:31; 45:1). Haman exercises a dangerous self-control: the rage is not released but compressed, making the subsequent explosion more calculated. <em>Zereš</em> is likely a Persian name — possibly <em>Zarish</em> or <em>Zaharish</em>, related to Old Persian <em>zaranya</em> (gold). The summons of 'friends and wife' mirrors the royal counsel structure of chs. 1-2: important decisions are made with an advisory circle. Haman reconstitutes his court in his home, with himself as king — the structural parallel that anticipates his downfall.</p>",
    "11": "<p><em>wayyᵉsappēr lāhem hāmān ʾet-kᵉḇôḏ ʿōšrô wᵉrōḇ bānāyw wᵉʾēt kol-ʾăšer giḏḏᵉlô hammelek wᵉʾēt ʾăšer nᵉśāʾô ʿal-haśśārîm wᵉʿaḇdê hammelek</em>: 'Haman recounted to them the glory of his riches, the number of his sons, and everything the king had done to honor him.' Three categories of boast: <em>kᵉḇôḏ ʿōšrô</em> (glory of his wealth), <em>rōḇ bānāyw</em> (multitude of his sons — ten are named in 9:7-10), and royal elevation above all princes. The threefold honor-catalogue is the standard ancient biography of a great man's achievement: wealth (economic power), sons (biological legacy), and royal status (political prestige). The sons are not incidental — in the ancient world many sons meant divine favor and household strength. But the exhaustive recitation of honors to his inner circle reveals the psychology: Haman requires constant external validation to maintain his sense of self, and no amount of honors is sufficient so long as one man withholds acknowledgment.</p>",
    "12": "<p><em>wayyōʾmer hāmān ʾap̄ lōʾ-hēḇîʾāh ʾestēr hammalḵāh ʿim-hammelek ʾel-hammiště ʾăšer-ʿāśāṯāh kî ʾim-ʾōṯî</em>: 'Haman said, moreover, Queen Esther brought no one but me to the banquet she gave with the king.' <em>ʾAp̄</em> (moreover, furthermore) introduces the crowning piece of the boast: even above wealth and sons, the exclusive dinner invitation. The honor is defined by exclusivity — 'none but me' with the king and queen. The verse's savage irony is invisible to Haman: the exclusive dinner that is his greatest boast is the setup for his accusation, disgrace, and execution. The gathering that he takes as proof of Esther's favor is the mechanism of his destruction — the honor that is simultaneously the death summons. The book's providential structure uses Haman's own pride to deliver him to his judgment.</p>",
    "13": "<p><em>wᵉḵol-zeh ʾênennû šōweh lî bᵉḵol-ʿēt ʾăšer ʾănî rōʾeh ʾet-morḏᵉḵay hayyᵉhûḏî yōšēḇ bᵉšaʿar hammelek</em>: 'yet all this is worth nothing (<em>ʾênennû šōweh lî</em>) to me whenever I see Mordecai the Jew sitting at the king's gate.' <em>ʾÊnennû šōweh lî</em> (it is not worth it to me) — the phrase of radical devaluation: wealth, sons, royal honor, and the queen's exclusive attention — all of it is negated by one man's presence. The label <em>hayyᵉhûḏî</em> (the Jew) attached to Mordecai's name is significant: Haman does not say 'Mordecai who will not bow,' he says 'Mordecai the Jew' — the grievance has already become ethnic rather than personal. The real conflict is not about Mordecai's individual conduct but about the existence of a people with a loyalty that supersedes imperial authority. The chapter's theological center: ethnic identity as the real source of Haman's obsession.</p>",
    "14": "<p><em>wattōʾmer lô zereš ʾišṯô wᵉḵol-ʾōhăḇāyw yēʿāśeh-ʿēṣ gāḇōah ḥămiššîm ʾammāh</em>: 'his wife Zeresh and all his friends said, let a gallows (<em>ʿēṣ</em>) be made, fifty cubits high.' <em>ʿEṣ</em> (wood, tree, gallows) — the word first appeared at 2:23 for the conspirators' execution. The same instrument now threatens Mordecai; it will ultimately hang Haman (7:9-10). The fifty-cubit height (approximately 22-23 meters) is conspicuously public — the gallows is designed to be visible throughout Susa as a monument to Haman's power and Mordecai's disgrace. The height's absurdity (nearly as tall as a modern five-story building) is characteristic of the book's comedy of imperial excess. <em>Wattōʾmar lô zereš baqšē mimmenû hammelek lᵉhāmān wᵉhēṭaḇ liḇbᵉḵā</em>: Zeresh urges Haman to request the execution from the king, and Haman's heart is good (<em>wayyîṭaḇ lip̄nê hāmān haddāḇār</em>) — the same <em>ṭôḇ</em> formula used for the king's royal approvals throughout chs. 1-3 here applied to Haman's pleasure in his wife's death-plan. The <em>ʿēṣ</em> thread that begins in 2:23, intensifies here, and resolves in 7:9-10 is the book's central gallows reversal: the instrument of death plotted against the innocent becomes the instrument of judgment against the guilty.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'esther')
    merge_comm(c, ORIG)
    save_comm('mkt-original', 'esther', c)
    total = sum(len(vs) for vs in ORIG.values())
    print(f'esther mkt-original: {total} verses written (ch1-5)')

if __name__ == '__main__':
    main()